const episodes = $input.all().map(e => e.json);
let wins = 0;
let losses = 0;
let breakevens = 0;
let total_pnl = 0;

episodes.forEach(e => {
  if (e.outcome_class === 'WIN') wins++;
  else if (e.outcome_class === 'LOSS') losses++;
  else breakevens++;

  if (e.profit_loss) total_pnl += parseFloat(e.profit_loss);
});

const total = episodes.length;
const winRate = total ? ((wins / total) * 100).toFixed(1) : 0;

const summary = {
  symbol: $('Webhook (RAG Trigger)').first().json.body.symbol,
  timeframe: $('Webhook (RAG Trigger)').first().json.body.timeframe || "H1",
  episodes_analyzed: total,
  win_rate_pct: winRate,
  total_pnl: total_pnl.toFixed(2),
  breakdown: `W: ${wins} | L: ${losses} | BE: ${breakevens}`,
  rag_context: `Históricamente en los últimos ${total} trades, se observa un win rate de ${winRate}%. El PNL total reciente es de ${total_pnl.toFixed(2)}. Favor de considerar esta estructura de riesgo reciente.`
};

return [{ json: summary }];
